CREATE VIEW `ads_center_book_channel_view` (`id`, `PlanCode`, `name`, `ApplyType`, `ChannelType`, `title`, `sort_name`, `FirstType`, `cfg_name`, `ClimbChartsType`, `RepetitionType`) AS SELECT `ods`.`a`.`id`, CASE WHEN (`ods`.`a`.`PlanCode` IS NULL) THEN '-' ELSE `ods`.`a`.`PlanCode` END AS `PlanCode`, `ods`.`a`.`name`, CASE WHEN (`ods`.`a`.`ApplyType` = 1) THEN '书城' WHEN (`ods`.`a`.`ApplyType` = 2) THEN '末页推' WHEN (`ods`.`a`.`ApplyType` = 3) THEN '详情页' WHEN (`ods`.`a`.`ApplyType` = 4) THEN '推书弹窗' WHEN (`ods`.`a`.`ApplyType` = 5) THEN '福利中心' WHEN (`ods`.`a`.`ApplyType` = 6) THEN '搜索中间页' WHEN (`ods`.`a`.`ApplyType` = 7) THEN 'VIP落地页' ELSE '-' END AS `ApplyType`, CASE WHEN (`ods`.`a`.`ChannelType` = 1) THEN '自定义' WHEN (`ods`.`a`.`ChannelType` = 2) THEN '特殊频道_分类频道' WHEN (`ods`.`a`.`ChannelType` = 3) THEN '特殊频道_榜单频道' WHEN (`ods`.`a`.`ChannelType` = 4) THEN '特殊频道_有声频道（限CORE1简体/繁体）' WHEN (`ods`.`a`.`ChannelType` = 5) THEN '特殊频道_猜你喜欢算法模型' WHEN (`ods`.`a`.`ChannelType` = 6) THEN 'Vip' ELSE '-' END AS `ChannelType`, concat(`ods`.`a`.`TitleId`, '_', `ods`.`d`.`name`, '_', `ods`.`d`.`Content`) AS `title`, CASE WHEN (`ods`.`b`.`Sort` IS NULL) THEN '【位序1】' ELSE (concat('【位序', `ods`.`b`.`Sort`, '】')) END AS `sort_name`, CASE WHEN (`ods`.`b`.`Sort` IS NULL) THEN (concat(`ods`.`a`.`templateId`, '_【', `ods`.`a`.`PlanCode`, '】')) WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 1)) THEN '推书_通用' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 2)) THEN '推书_限时整本免费' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 3)) THEN '推书_限时章节免费' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 4)) THEN '专题榜单' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 5)) THEN '分类标签榜单' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 6)) THEN '一口价榜单' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 7)) THEN '书籍介绍' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 8)) THEN '评论区' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 9)) THEN '粉丝榜' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 10)) THEN '作者作品' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 11)) THEN '首章预览' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 12)) THEN '推书-定向推送（仅简体）' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 13)) THEN '折扣榜单' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 14)) THEN '特殊_排行榜' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 15)) THEN '特殊_金刚区' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 16)) THEN '推书_限时整本免费(AD)' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 17)) THEN '推书_限时章节免费(AD)' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 18)) THEN '推书_VIP' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 19)) THEN '最近在看VIP作品' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`FirstType` = 20)) THEN '推书_有声书' ELSE '' END AS `FirstType`, CASE WHEN (`ods`.`b`.`Sort` IS NULL) THEN `ods`.`a`.`name` ELSE (concat(`ods`.`c`.`id`, '_', `ods`.`c`.`name`)) END AS `cfg_name`, CASE WHEN (`ods`.`b`.`Sort` IS NULL) THEN '' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`ClimbChartsType` = 0)) THEN '不爬榜' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`ClimbChartsType` = 1)) THEN '新书榜' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`ClimbChartsType` = 2)) THEN '榜1' WHEN ((`ods`.`b`.`Sort` IS NOT NULL) AND (`ods`.`c`.`ClimbChartsType` = 3)) THEN '榜2' ELSE '-' END AS `ClimbChartsType`, CASE WHEN (`ods`.`a`.`RepetitionType` = 1) THEN '排重' WHEN (`ods`.`a`.`RepetitionType` = 2) THEN '不排重' ELSE '-' END AS `RepetitionType`
FROM `ods`.`ods_tidb_readernovel_tidb_tag_center_book_channel` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_readernovel_tidb_tag_center_channel_list` AS `b` ON (`ods`.`a`.`id` = `ods`.`b`.`ChannelId`) AND (`ods`.`b`.`DelStatus` = 0) LEFT OUTER JOIN `ods`.`ods_tidb_readernovel_tidb_tag_center_book_list` AS `c` ON `ods`.`c`.`id` = `ods`.`b`.`ListId` LEFT OUTER JOIN `ods`.`ods_tidb_readernovel_tidb_tag_center_action_title` AS `d` ON `ods`.`d`.`id` = `ods`.`a`.`TitleId` ORDER BY `ods`.`b`.`Sort` ASC ;